package main

// Compliant: Refactored into smaller, focused functions
func processUserData(users []User, filters map[string]interface{}) []User {
    var result []User
    for _, user := range users {
        if shouldIncludeUser(user, filters) {
            result = append(result, user)
        }
    }
    return result
}

func shouldIncludeUser(user User, filters map[string]interface{}) bool {
    if !user.Active || !user.HasPermission("read") {
        return false
    }

    return matchesAgeFilter(user, filters) &&
           matchesDepartmentFilter(user, filters) &&
           matchesSalaryFilter(user, filters)
}

func matchesAgeFilter(user User, filters map[string]interface{}) bool {
    age, exists := filters["age"].(int)
    return !exists || user.Age >= age
}

func matchesDepartmentFilter(user User, filters map[string]interface{}) bool {
    dept, exists := filters["department"].(string)
    return !exists || user.Department == dept
}

func matchesSalaryFilter(user User, filters map[string]interface{}) bool {
    salary, exists := filters["salary"].(float64)
    return !exists || user.Salary >= salary
}
